const PLACEMENT=[{"id": 0, "level": "A1", "q": "She ___ my sister.", "options": ["am", "is", "are", "be"], "answer": 1}, {"id": 1, "level": "A1", "q": "I ___ from Mexico.", "options": ["is", "am", "are", "do"], "answer": 1}, {"id": 2, "level": "A1", "q": "___ you like coffee?", "options": ["Are", "Do", "Does", "Is"], "answer": 1}, {"id": 3, "level": "A1", "q": "There ___ two books.", "options": ["is", "are", "am", "be"], "answer": 1}, {"id": 4, "level": "A2", "q": "I have lived here ___ 2020.", "options": ["for", "since", "during", "ago"], "answer": 1}, {"id": 5, "level": "A2", "q": "You ___ see a doctor.", "options": ["should", "can to", "must to", "are"], "answer": 0}, {"id": 6, "level": "A2", "q": "If it rains, we ___ home.", "options": ["stay", "will stay", "stayed", "staying"], "answer": 1}, {"id": 7, "level": "A2", "q": "This bag is ___ than mine.", "options": ["heavy", "heavier", "heaviest", "more heavy"], "answer": 1}, {"id": 8, "level": "B1", "q": "When I arrived, she ___ already left.", "options": ["has", "had", "was", "did"], "answer": 1}, {"id": 9, "level": "B1", "q": "The report ___ yesterday.", "options": ["finished", "was finished", "has finish", "is finishing"], "answer": 1}, {"id": 10, "level": "B1", "q": "He said he ___ busy.", "options": ["is", "was", "has", "will"], "answer": 1}, {"id": 11, "level": "B1", "q": "I wish I ___ more time.", "options": ["have", "had", "will have", "having"], "answer": 1}, {"id": 12, "level": "B2", "q": "Had I known, I ___ earlier.", "options": ["would call", "would have called", "called", "had called"], "answer": 1}, {"id": 13, "level": "B2", "q": "The proposal, ___ was ambitious, was approved.", "options": ["who", "which", "that", "where"], "answer": 1}, {"id": 14, "level": "B2", "q": "The data ___ that demand is increasing.", "options": ["suggests", "suggest", "suggesting", "to suggest"], "answer": 0}, {"id": 15, "level": "B2", "q": "Not only ___ the issue, but she solved it.", "options": ["she identified", "did she identify", "she did identify", "identified she"], "answer": 1}, {"id": 16, "level": "C1", "q": "The findings are significant; ___, they require cautious interpretation.", "options": ["therefore", "however", "because", "so"], "answer": 1}, {"id": 17, "level": "C1", "q": "The speaker’s argument was nuanced, ___ somewhat speculative.", "options": ["albeit", "despite", "whereas", "unless"], "answer": 0}, {"id": 18, "level": "C1", "q": "This policy may yield benefits, provided that risks ___ mitigated.", "options": ["are", "be", "were", "being"], "answer": 1}, {"id": 19, "level": "C1", "q": "The author implies rather than ___ states the conclusion.", "options": ["explicit", "explicitly", "explicate", "explicitness"], "answer": 1}, {"id": 20, "level": "C2", "q": "Her reply was deliberately understated, almost ___.", "options": ["laconic", "literal", "basic", "random"], "answer": 0}, {"id": 21, "level": "C2", "q": "The argument hinges on a subtle ___ between correlation and causation.", "options": ["distinction", "distance", "distraction", "distortion"], "answer": 0}, {"id": 22, "level": "C2", "q": "The proposal is viable, ___ politically contentious.", "options": ["notwithstanding", "albeit", "thereby", "henceforth"], "answer": 1}, {"id": 23, "level": "C2", "q": "A more idiomatic response would be: “I’m not entirely ___.”", "options": ["sell", "sold", "selling", "to sell"], "answer": 1}];
let currentId=null,state=null,selectedLevel='A1',activeLesson=null,lessonStep=0,speakingSession=null,recognition=null,micOn=false,autoListen=false;
const KEY='fluentia_ia_profiles';
function uid(){return Date.now().toString(36)+Math.random().toString(36).slice(2,8)}
function esc(s){return String(s??'').replace(/[&<>"]/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;'}[c]))}
function toast(msg){let t=document.getElementById('toast');t.textContent=msg;t.style.display='block';clearTimeout(t._timer);t._timer=setTimeout(()=>t.style.display='none',2300)}
function loadProfiles(){try{return JSON.parse(localStorage.getItem(KEY)||'[]')}catch(e){return []}}
function saveProfiles(p){localStorage.setItem(KEY,JSON.stringify(p))}
function defaultState(profile){return {profile,xp:0,streak:0,lastDay:'',daily:{},doneModules:[],moduleScores:{},badges:[],vocab:[],listeningDone:[],speakingSessions:[],placement:null,certificates:[],examResults:[]}}
function save(){if(!state)return;localStorage.setItem('fluentia_state_'+state.profile.id,JSON.stringify(state));document.getElementById('xpPill').textContent=(state.xp||0)+' XP'}
function loadState(id){let raw=localStorage.getItem('fluentia_state_'+id);return raw?JSON.parse(raw):null}
function renderProfiles(){let box=document.getElementById('profiles');let ps=loadProfiles();box.innerHTML=ps.length?ps.map(p=>`<div class="profile"><div class="avatar">${esc((p.name||'U')[0]).toUpperCase()}</div><div class="meta"><strong>${esc(p.name)}</strong><small>${esc(p.level)} · ${esc(p.goal)}</small></div><button class="btn small" onclick="openProfile('${p.id}')">Abrir</button></div>`).join(''):'<p class="tiny">Aún no hay estudiantes guardados en este navegador.</p>'}
function createProfile(){let name=(document.getElementById('newName').value||'').trim()||'Estudiante';let level=document.getElementById('newLevel').value;let goal=document.getElementById('newGoal').value;let profile={id:uid(),name,level:level==='Placement'?'Sin nivel':level,goal,created:new Date().toISOString()};let ps=loadProfiles();ps.push(profile);saveProfiles(ps);state=defaultState(profile);currentId=profile.id;save();initApp();if(level==='Placement')setTimeout(openPlacement,350)}
function openProfile(id){let s=loadState(id);let ps=loadProfiles();if(!s){let p=ps.find(x=>x.id===id);s=defaultState(p)}state=s;currentId=id;initApp()}
function initApp(){document.getElementById('auth').classList.add('hidden');document.getElementById('app').classList.remove('hidden');document.getElementById('topSub').textContent=`${state.profile.name} · ${state.profile.level}`;selectedLevel=state.profile.level&&LEVELS.includes(state.profile.level)?state.profile.level:'A1';checkDay();save();renderAll();}
function checkDay(){let today=new Date().toDateString();if(state.lastDay!==today){state.daily={};state.lastDay=today;state.streak=(state.streak||0)+1;save()}}
document.querySelectorAll('.nav button').forEach(b=>b.addEventListener('click',()=>showScreen(b.dataset.nav)));
function showScreen(id){document.querySelectorAll('.screen').forEach(s=>s.classList.remove('active'));document.getElementById(id).classList.add('active');document.querySelectorAll('.nav button').forEach(b=>b.classList.toggle('active',b.dataset.nav===id));if(id==='home')renderHome();if(id==='modules')renderModules();if(id==='speaking')renderSpeaking();if(id==='practice')renderPractice();if(id==='progress')renderProgress();}
function renderAll(){renderHome();renderModules();renderSpeaking();renderPractice();renderProgress()}
function dailyNote(){return NOTES[Math.floor(Date.now()/86400000)%NOTES.length]}
function calcDays(){let map={A1:420,A2:330,B1:240,B2:150,C1:90,C2:45,'Sin nivel':240};let base=map[state.profile.level]||240;let min=state.profile.minutes||90;return Math.max(45,Math.round(base*90/min))}
function pct(){return Math.round((state.doneModules.length/(LEVELS.length*100))*100)}
function renderHome(){let n=dailyNote();let d=state.daily||{};let placementNeeded=!state.placement&&state.profile.level==='Sin nivel';document.getElementById('home').innerHTML=`<div class="hero"><h2>Tu ruta hacia inglés bilingüe</h2><p>Objetivo estimado: ${calcDays()} días con práctica diaria intensa. Completa speaking, listening, vocabulario y una misión de módulo cada día.</p></div><div class="grid2"><div class="card"><div class="kicker">Avance total</div><div class="metric">${pct()}%</div><div class="bar"><span style="width:${pct()}%"></span></div><p class="tiny">${state.doneModules.length} de ${LEVELS.length*100} módulos completados.</p></div><div class="card"><div class="kicker">Nivel actual</div><div class="metric">${esc(state.profile.level)}</div><p class="tiny">${esc(state.profile.goal)} · racha ${state.streak||0} días</p><button class="btn secondary full" onclick="openPlacement()">🧭 Test de ubicación</button></div></div>${placementNeeded?`<div class="warnbox"><b>Empieza con diagnóstico.</b><br>Haz el test de ubicación para que la app recomiende tu nivel inicial.</div>`:''}<div class="daily-card"><div class="kicker">Lectura diaria</div><h3>${esc(n.title)}</h3><p>${esc(n.body)}</p><div class="note"><b>Reto:</b> ${esc(n.challenge)}</div><div class="row" style="margin-top:10px"><button class="btn small gold" onclick="speakText('${esc(n.body)}')">▶ Escuchar</button><button class="btn small secondary" onclick="addWord('consistency','constancia','Daily note')">+ consistency</button></div></div><div class="card"><h3>Misiones de hoy</h3>${dailyTask('speaking','🎙️','Speaking conversacional','Habla con el coach y recibe corrección final.')}${dailyTask('listening','🎧','Listening activo','Escucha, responde y revisa palabras clave.')}${dailyTask('module','🗺️','Avanzar en la ruta','Completa una lección del mapa.')}${dailyTask('vocab','🔤','Vocabulario','Agrega o repasa al menos 5 palabras.')}${dailyTask('writing','✍️','Writing mini task','Escribe 80–120 palabras y revisa conectores.')}</div><div class="cover"><h2>Aprende como juego</h2><p>Desbloquea mundos, gana medallas, supera jefes de nivel y emite certificados internos cuando demuestres competencia.</p><button class="btn gold" style="margin-top:12px" onclick="showScreen('modules')">Ir a la ruta</button></div>`}
function dailyTask(id,ico,title,sub){let done=(state.daily||{})[id];return `<div class="task ${done?'done':''}"><div class="ticon">${ico}</div><div><strong>${title}</strong><small>${sub}</small></div><div class="check">✓</div></div>`}
function markDaily(id){state.daily=state.daily||{};state.daily[id]=true;save()}
function renderModules(){let lvl=selectedLevel;let list=TOPICS.filter(t=>t.level===lvl);let doneCount=list.filter(t=>state.doneModules.includes(t.id)).length;let unlocked=Math.min(doneCount+1,100);document.getElementById('modules').innerHTML=`<div class="cover"><h2>Ruta de módulos</h2><p>Avanza misión por misión. Cada lección incluye explicación en inglés/español en A1–A2, lectura, listening, vocabulario, speaking y mini test temático.</p></div><div class="card compact"><div class="chips">${LEVELS.map(l=>`<button class="chip ${l===lvl?'active':''}" onclick="selectedLevel='${l}';renderModules()">${l}</button>`).join('')}</div></div><div class="card"><h3>Medallas de ${lvl}</h3><div class="badge-shelf">${medalsForLevel(lvl,doneCount)}</div><div class="bar"><span style="width:${doneCount}%"></span></div><p class="tiny">${doneCount}/100 misiones del mundo ${lvl}. La siguiente misión desbloqueada es ${Math.min(doneCount+1,100)}.</p></div><div class="world"><div class="world-head"><div><h3>Mundo ${lvl}</h3><div class="legend"><span>🟢 completado</span><span>🟡 actual</span><span>🔒 bloqueado</span></div></div><span class="xp">⚡ ${doneCount*20} XP</span></div><div class="map">${list.map(t=>nodeHTML(t,doneCount)).join('')}</div></div>`}
function medalsForLevel(lvl,count){let ms=[['🥉','Bronce',5],['🥈','Plata',20],['🥇','Oro',50],['💎','Diamante',80],['👑','Maestría',100]];return ms.map(m=>`<div class="medal ${count>=m[2]?'':'lock'}"><div class="micon">${m[0]}</div><b>${m[1]}</b><small>${m[2]} módulos</small></div>`).join('')}
function nodeHTML(t,doneCount){let done=state.doneModules.includes(t.id);let current=!done&&t.n===doneCount+1;let locked=!done&&!current;return `<div class="node ${done?'done':current?'current':'locked'}"><button class="node-btn" onclick="${locked?'toast(\'Completa la misión anterior para desbloquear esta.\')':`openLesson('${t.id}')`}">${done?'✓':locked?'🔒':t.n}</button><small>${esc(t.title)}</small></div>`}
function openLesson(id){activeLesson=TOPICS.find(t=>t.id===id);lessonStep=0;renderLesson()}
function renderLesson(){let t=activeLesson;let modal=document.getElementById('lessonModal');let steps=['Briefing','Explicación','Reading','Listening','Vocab','Speaking','Ejercicios','Mini test'];modal.innerHTML=`<div class="lesson-sheet"><div class="lesson-hero"><div class="row" style="justify-content:space-between"><span class="pill dark">${t.level} · ${t.phase} · ${t.skill}</span><button class="btn small secondary" onclick="closeLesson()">Cerrar</button></div><h2>${esc(t.title)}</h2><p>Mission ${t.n}: domina ${esc(t.grammar)} en contexto de ${esc(t.context)}.</p></div><div class="lesson-nav">${steps.map((s,i)=>`<button class="lesson-tab ${i===lessonStep?'active':''}" onclick="lessonStep=${i};renderLesson()">${i+1}. ${s}</button>`).join('')}</div><div>${steps.map((s,i)=>`<div class="step ${i===lessonStep?'active':''}">${lessonStepHTML(t,i)}</div>`).join('')}</div><div class="row" style="margin-top:12px;justify-content:space-between"><button class="btn secondary" onclick="lessonStep=Math.max(0,lessonStep-1);renderLesson()">← Atrás</button><button class="btn" onclick="lessonStep=Math.min(7,lessonStep+1);renderLesson()">Siguiente →</button></div></div>`;modal.classList.add('show')}
function closeLesson(){document.getElementById('lessonModal').classList.remove('show');activeLesson=null}
function lessonStepHTML(t,i){return [briefingHTML,explanationHTML,readingHTML,listeningHTML,vocabHTML,speakingMiniHTML,exercisesHTML,testHTML][i](t)}
function bilingualText(t){if(t.level==='A1'||t.level==='A2')return `<div class="bilingual"><div class="langbox"><b>🇪🇸 Explicación en español</b><p>${spanishExplanation(t)}</p></div><div class="langbox"><b>🇺🇸 Explanation in English</b><p>${englishExplanation(t)}</p></div></div>`;return `<div class="langbox"><b>English explanation</b><p>${englishExplanation(t)}</p><p class="tiny">Tip en español: enfócate en usar la estructura dentro de una situación real, no solo en memorizar reglas.</p></div>`}
function spanishExplanation(t){if(t.grammar==='Verb to be')return 'El verbo to be significa ser o estar. En presente se usa am con I, is con he/she/it y are con you/we/they. Sirve para decir quién eres, cómo estás, de dónde eres, tu profesión, edad, descripción o ubicación.';return `En esta lección aprenderás ${t.grammar}. La idea es usar la estructura para comunicarte en situaciones de ${t.context}. Primero identifica el sujeto, después usa la forma correcta y finalmente agrega información clara.`}
function englishExplanation(t){if(t.grammar==='Verb to be')return 'The verb to be means ser or estar. Use am with I, is with he/she/it, and are with you/we/they. It helps you introduce yourself, describe people, say where someone is from, and explain feelings or locations.';return `This lesson helps you use ${t.grammar} in ${t.context}. Focus on meaning first, then form, then pronunciation. A strong answer includes a clear subject, the correct structure, and a useful detail.`}
function structureHTML(t){if(t.grammar==='Verb to be')return `<div class="example"><b>Structure</b><br>I + am + complement → I am Diego.<br>He/She/It + is + complement → She is a manager.<br>You/We/They + are + complement → They are from Canada.</div><div class="example"><b>Negative</b><br>I am not tired. · He is not here. · They are not ready.</div><div class="example"><b>Question</b><br>Are you a student? Yes, I am. / No, I am not.<br>Is she Mexican? Yes, she is.</div>`;return `<div class="example"><b>Structure</b><br>${esc(t.grammar)} + clear context + useful detail.</div><div class="example"><b>Model</b><br>In ${esc(t.context)}, I can use this structure to give precise information and sound more natural.</div>`}
function briefingHTML(t){return `<div class="card"><h3>🎮 Mission briefing</h3><p>Tu misión es desbloquear la habilidad <b>${esc(t.grammar)}</b> para usarla en <b>${esc(t.context)}</b>.</p><div class="video-card"><div><div class="play">▶</div><p>Visual capsule: ${esc(t.grammar)}</p></div></div><button class="btn gold full" style="margin-top:10px" onclick="speakText('${esc('Today we will practice '+t.grammar+' in '+t.context+'. Listen, repeat, answer, and complete the mini test.')}')">Escuchar cápsula</button></div>`}
function explanationHTML(t){return `<div class="card explain"><h3>📘 Tema / Topic</h3>${bilingualText(t)}<h4>Estructura</h4>${structureHTML(t)}<h4>Examples / Ejemplos</h4><div class="examples">${examplesFor(t).map(e=>`<div class="example"><b>${esc(e.en)}</b><br><span class="muted">${esc(e.es)}</span><br><small>${esc(e.why)}</small></div>`).join('')}</div><div class="warnbox"><b>Error común:</b> ${esc(commonMistake(t))}</div></div>`}
function examplesFor(t){if(t.grammar==='Verb to be')return [{en:'I am a quality supervisor.',es:'Soy supervisor de calidad.',why:'I usa am.'},{en:'She is from Puebla.',es:'Ella es de Puebla.',why:'She usa is.'},{en:'They are ready for the meeting.',es:'Ellos están listos para la reunión.',why:'They usa are.'},{en:'Are you available today?',es:'¿Estás disponible hoy?',why:'En pregunta, el verbo va antes del sujeto.'}];return [{en:`I use ${t.grammar} when I talk about ${t.context}.`,es:`Uso ${t.grammar} cuando hablo de ${t.context}.`,why:'Conecta gramática con contexto.'},{en:`This structure helps me sound clear and natural.`,es:'Esta estructura me ayuda a sonar claro y natural.',why:'Explica utilidad comunicativa.'},{en:`For example, I can give a reason and a detail.`,es:'Por ejemplo, puedo dar una razón y un detalle.',why:'Agrega información para fluidez.'}]}
function commonMistake(t){if(t.grammar==='Verb to be')return 'No digas “I are” o “she am”. Usa I am, he/she/it is, you/we/they are.';return 'No traduzcas palabra por palabra desde español. Construye la frase con sujeto + estructura + idea principal + detalle.'}
function readingText(t){if(t.grammar==='Verb to be')return 'My name is Daniel. I am from Mexico, and I am an English student. My sister is a doctor, and my parents are teachers. We are happy because English is useful for work, travel, and new opportunities.';let base=`In ${t.context}, communication is easier when you use ${t.grammar} with clear examples. A confident speaker gives information, adds a reason, and checks that the listener understands. This habit makes English more natural and useful in real life.`;return t.level==='A1'||t.level==='A2'?base:base+' Advanced learners also notice tone, register, and precision. They choose words carefully and adapt the message to the audience.'}
function readingHTML(t){let txt=readingText(t);return `<div class="card"><h3>📖 Reading del tema</h3><p class="tiny">Toca o pasa sobre una palabra para agregarla al vocabulario.</p><div class="reading">${smartWords(txt,t)}</div><div class="row" style="margin-top:10px"><button class="btn gold" onclick="speakText('${esc(txt)}')">▶ Escuchar lectura</button><button class="btn secondary" onclick="markDaily('module');toast('Lectura completada')">Marcar lectura</button></div></div>`}
function smartWords(txt,t){return txt.split(/(\s+)/).map(w=>{let clean=w.replace(/[^A-Za-z'-]/g,'');if(clean.length>4)return `<span class="word" onclick="addWord('${esc(clean.toLowerCase())}','','${esc(t.title)}')">${esc(w)}</span>`;return esc(w)}).join('')}
function listeningHTML(t){let txt=readingText(t);return `<div class="card"><h3>🎧 Listening</h3><p>Escucha la lectura. Después escribe la frase clave que recuerdes.</p><button class="btn gold full" onclick="speakText('${esc(txt)}')">▶ Reproducir audio</button><div class="qa"><b>Dictado / Dictation</b><textarea id="dict_${t.id}" class="field" placeholder="Write what you understood..."></textarea><button class="btn small secondary" onclick="checkDictation('${t.id}','${esc(txt)}')">Revisar</button></div></div>`}
function checkDictation(id,txt){let v=(document.getElementById('dict_'+id).value||'').toLowerCase();let keywords=txt.toLowerCase().split(/\W+/).filter(w=>w.length>5).slice(0,6);let hits=keywords.filter(k=>v.includes(k)).length;toast(`Listening: ${hits}/${keywords.length} palabras clave detectadas`);markDaily('listening');state.xp+=10;save()}
function vocabHTML(t){let words=vocabFor(t);return `<div class="card"><h3>🔤 Vocabulario clave</h3><div class="list">${words.map(w=>`<div class="task"><div class="ticon">🔹</div><div><strong>${esc(w[0])}</strong><small>${esc(w[1])}</small></div><button class="btn small secondary" onclick="addWord('${esc(w[0])}','${esc(w[1])}','${esc(t.title)}')">Agregar</button></div>`).join('')}</div></div>`}
function vocabFor(t){if(t.grammar==='Verb to be')return [['ready','listo'],['available','disponible'],['student','estudiante'],['manager','gerente'],['from','de / desde'],['tired','cansado'],['happy','feliz'],['busy','ocupado']];return [[t.grammar.toLowerCase(),'estructura principal'],[t.context,'contexto'],['reason','razón'],['detail','detalle'],['clear','claro'],['natural','natural'],['example','ejemplo'],['improve','mejorar']]}
function speakingMiniHTML(t){return `<div class="card"><h3>🎙️ Speaking del módulo</h3><p>Responde en voz alta usando <b>${esc(t.grammar)}</b>.</p><div class="note"><b>Prompt:</b> ${speakingPrompt(t)}</div><textarea id="lessonSpeak_${t.id}" class="field" placeholder="Tu respuesta aparecerá aquí si usas micrófono..."></textarea><div class="row" style="margin-top:10px"><button class="btn hot" onclick="startMicToField('lessonSpeak_${t.id}')">🎙️ Activar micrófono</button><button class="btn secondary" onclick="speakText('${esc(speakingPrompt(t))}')">Escuchar prompt</button></div></div>`}
function speakingPrompt(t){if(t.grammar==='Verb to be')return 'Introduce yourself using am, is, and are. Example: I am Diego. My team is ready. We are learning English.';return `Give a short answer about ${t.context} using ${t.grammar}. Include one reason and one example.`}
function exercisesHTML(t){let ex=exerciseSet(t);return `<div class="card"><h3>🧠 Ejercicios explicados</h3>${ex.explained.map(e=>`<div class="example"><b>${esc(e.q)}</b><br>Respuesta: <b>${esc(e.a)}</b><br><small>${esc(e.why)}</small></div>`).join('')}<h3>✍️ Ahora tú resuelve</h3>${ex.practice.map((q,i)=>`<div class="qa"><b>${i+1}. ${esc(q)}</b><input class="field" id="prac_${t.id}_${i}" placeholder="Write your answer..."></div>`).join('')}<button class="btn secondary full" onclick="showPracticeAnswers('${t.id}')">Ver respuestas sugeridas</button><div id="ans_${t.id}"></div></div>`}
function exerciseSet(t){if(t.grammar==='Verb to be')return {explained:[{q:'Complete: I ___ an English student.',a:'am',why:'I siempre usa am.'},{q:'Complete: She ___ from Canada.',a:'is',why:'She usa is.'},{q:'Make a question: you / ready?',a:'Are you ready?',why:'En preguntas con to be, el verbo va antes del sujeto.'}],practice:['I ___ from Mexico.','They ___ in a meeting.','My brother ___ very busy.','Make negative: I am tired.','Make question: she / available?','Write 3 sentences about yourself using am/is/are.']};return {explained:[{q:`Use ${t.grammar} in one sentence.`,a:`I can use ${t.grammar} to talk about ${t.context}.`,why:'La frase conecta forma + contexto.'},{q:'Add a reason.',a:'I use it because it makes my message clear.',why:'Because introduce la razón.'},{q:'Add an example.',a:'For example, I can explain a problem politely.',why:'For example fortalece fluidez.'}],practice:[`Write one sentence using ${t.grammar}.`,`Write a question about ${t.context}.`,`Write a negative sentence.`,`Add because to explain your idea.`,`Add for example with a real case.`,`Write a 4-line mini dialogue.`]}}
function showPracticeAnswers(id){let t=TOPICS.find(x=>x.id===id);let ans=t.grammar==='Verb to be'?['am','are','is','I am not tired.','Is she available?','I am Diego. My company is busy. We are ready.']:[`I use ${t.grammar} in ${t.context}.`,`How can I use this in ${t.context}?`,`I do not want to translate word by word.`,`I need this because I want to sound natural.`,`For example, I can use it in a meeting.`,`A: Can you explain? B: Yes, I can give an example.`];document.getElementById('ans_'+id).innerHTML='<div class="note"><b>Respuestas sugeridas:</b><br>'+ans.map((a,i)=>`${i+1}. ${esc(a)}`).join('<br>')+'</div>'}
function testHTML(t){let qs=testFor(t);return `<div class="card"><h3>✅ Mini test del tema</h3><p class="tiny">Este test cambia según la lección.</p>${qs.map((q,i)=>`<div class="placement-q"><b>${i+1}. ${esc(q.q)}</b>${q.options.map((o,j)=>`<button class="option" onclick="answerMini('${t.id}',${i},${j},${q.a},this)">${esc(o)}</button>`).join('')}</div>`).join('')}<button class="btn green full" onclick="completeModule('${t.id}')">Completar misión</button></div>`}
function testFor(t){if(t.grammar==='Verb to be')return [{q:'Choose the correct sentence.',options:['I are Diego.','I am Diego.','I is Diego.'],a:1},{q:'Complete: She ___ a manager.',options:['am','is','are'],a:1},{q:'Complete: They ___ ready.',options:['is','are','am'],a:1},{q:'Make a question with “you / available”.',options:['Are you available?','You are available?','Is you available?'],a:0},{q:'Negative form of “I am tired”.',options:['I am not tired.','I not am tired.','I do not am tired.'],a:0}];return [{q:`What is the focus of this lesson?`,options:[t.grammar,'Random vocabulary','Only translation'],a:0},{q:`Best context for this module?`,options:[t.context,'Cooking only','Sports only'],a:0},{q:'A strong answer should include...',options:['subject + idea + detail','only one word','Spanish word order'],a:0},{q:'Which connector gives a reason?',options:['because','although','however'],a:0},{q:'Which phrase introduces an example?',options:['For example','Never mind','At least'],a:0}]}
function answerMini(id,i,j,a,btn){let wrap=btn.parentElement;wrap.querySelectorAll('.option').forEach(b=>b.disabled=true);btn.classList.add(j===a?'correct':'bad');if(j===a){state.moduleScores[id]=(state.moduleScores[id]||0)+1;state.xp+=3}else{wrap.querySelectorAll('.option')[a].classList.add('correct')}save()}
function completeModule(id){let t=TOPICS.find(x=>x.id===id);if(!state.doneModules.includes(id)){state.doneModules.push(id);state.xp+=t.xp;markDaily('module');awardBadges(t.level);save();toast(`Misión completada +${t.xp} XP`)}closeLesson();renderModules();renderHome()}
function awardBadges(level){let count=TOPICS.filter(t=>t.level===level&&state.doneModules.includes(t.id)).length;[[5,'Bronce'],[20,'Plata'],[50,'Oro'],[80,'Diamante'],[100,'Maestría']].forEach(([n,name])=>{let id=level+'-'+name;if(count>=n&&!state.badges.includes(id)){state.badges.push(id);setTimeout(()=>toast(`🏅 Medalla desbloqueada: ${name} ${level}`),300)}})}
function addWord(word,translation,source){word=String(word||'').toLowerCase();if(!word)return;state.vocab=state.vocab||[];if(!state.vocab.find(v=>v.word===word)){state.vocab.push({word,translation,source,date:new Date().toISOString(),level:selectedLevel});state.xp+=5;markDaily('vocab');save();toast(`Agregada: ${word}`)}else toast('Ya está en tu vocabulario')}
function speakText(text,cb){
  try{
    window.speechSynthesis.cancel();
    let u=new SpeechSynthesisUtterance(text);
    u.lang='en-US';
    u.rate=.95;
    u.pitch=1.02;
    u.onend=()=>cb&&cb();
    u.onerror=()=>cb&&cb();
    window.speechSynthesis.speak(u);
  }catch(e){cb&&cb()}
}
function speechSupport(){
  let SR=window.SpeechRecognition||window.webkitSpeechRecognition;
  return {
    supported:!!SR,
    secure:(window.isSecureContext===true || location.hostname==='localhost' || location.hostname==='127.0.0.1'),
    hasMedia:!!(navigator.mediaDevices&&navigator.mediaDevices.getUserMedia),
    ua:navigator.userAgent||''
  }
}
function getRecognizer(){
  let SR=window.SpeechRecognition||window.webkitSpeechRecognition;
  if(!SR)return null;
  let r=new SR();
  r.lang='en-US';
  r.interimResults=true;
  r.continuous=true;
  r.maxAlternatives=1;
  return r;
}
async function ensureMic(){
  let s=speechSupport();
  if(!s.secure){toast('El micrófono requiere HTTPS. Abre la app desde https://fluentia-ia.netlify.app/');return false}
  if(!s.hasMedia){toast('Tu navegador no expone acceso al micrófono. Prueba Chrome o Edge actualizados.');return false}
  try{
    let stream=await navigator.mediaDevices.getUserMedia({audio:{echoCancellation:true,noiseSuppression:true,autoGainControl:true}});
    stream.getTracks().forEach(t=>t.stop());
    return true;
  }catch(e){
    let msg='Permiso de micrófono bloqueado.';
    if(e && e.name==='NotFoundError') msg='No encontré un micrófono disponible.';
    if(e && e.name==='NotAllowedError') msg='Permiso denegado. Actívalo en configuración del sitio.';
    toast(msg);
    let st=document.getElementById('micStatus');if(st)st.textContent=msg;
    return false;
  }
}
async function startMicToField(fieldId){
  let ok=await ensureMic();if(!ok)return;
  let r=getRecognizer();
  if(!r){toast('Dictado web no disponible. Usa el botón de teclado por voz del celular o Chrome/Edge.');return}
  let field=document.getElementById(fieldId);let finalText='';
  r.onstart=()=>toast('Escuchando...');
  r.onresult=e=>{let interim='';for(let i=e.resultIndex;i<e.results.length;i++){let txt=e.results[i][0].transcript;if(e.results[i].isFinal)finalText+=txt+' ';else interim+=txt}field.value=(finalText+interim).trim()};
  r.onerror=e=>toast('Micrófono: '+friendlyMicError(e.error));
  r.onend=()=>{};
  try{r.start()}catch(e){toast('No pude iniciar el dictado. Recarga la página e intenta otra vez.')}
}
function friendlyMicError(error){
  const map={
    'not-allowed':'permiso denegado',
    'service-not-allowed':'servicio de dictado bloqueado',
    'no-speech':'no detecté voz clara',
    'audio-capture':'no encuentro micrófono',
    'network':'servicio de dictado sin conexión',
    'aborted':'dictado interrumpido'
  };
  return map[error]||error||'error de micrófono';
}
function renderSpeaking(){
  let sup=speechSupport();
  document.getElementById('speaking').innerHTML=`<div class="cover"><h2>Speaking Coach</h2><p>Conversación guiada: el coach responde tus ideas, te corrige y te da frases más naturales. Activa el micrófono y habla; al detectar una pausa, la app envía tu respuesta automáticamente.</p></div>
  <div class="card coach-panel"><h3>Elige una conversación</h3><p class="tiny">Para que el micrófono funcione, abre la app directamente desde Chrome, Edge o Safari en HTTPS, no desde vista previa de WhatsApp/Archivos.</p>
    <select id="spScenario" class="field">
      <option>Job interview</option><option>Daily conversation</option><option>Business meeting</option><option>Hotel problem</option><option>Audit and compliance</option><option>TOEFL-style independent speaking</option>
    </select>
    <div class="grid2" style="margin-top:10px"><button class="btn full" onclick="startSpeakingSession()">Iniciar conversación</button><button class="btn secondary full" onclick="runMicDiagnostic()">Probar micrófono</button></div>
    <div id="micDiag" class="tiny" style="margin-top:8px">Estado: ${sup.secure?'HTTPS seguro':'No seguro'} · Dictado: ${sup.supported?'compatible':'no detectado'} · Audio: ${sup.hasMedia?'disponible':'no disponible'}</div>
  </div><div id="speakArea"></div>`;
}
async function runMicDiagnostic(){
  let sup=speechSupport();
  let lines=[];
  lines.push(sup.secure?'✅ HTTPS correcto':'❌ Abre con HTTPS');
  lines.push(sup.hasMedia?'✅ API de micrófono disponible':'❌ Micrófono no disponible en este navegador');
  lines.push(sup.supported?'✅ Dictado SpeechRecognition detectado':'⚠️ Dictado automático no detectado; usa modo escritura o teclado por voz');
  let ok=await ensureMic();
  lines.push(ok?'✅ Permiso de micrófono concedido':'❌ Permiso de micrófono no concedido');
  let box=document.getElementById('micDiag'); if(box)box.innerHTML=lines.join('<br>');
}
function startSpeakingSession(){
  let sc=document.getElementById('spScenario').value;
  speakingSession={scenario:sc,turn:0,msgs:[{role:'ai',text:`Hi, I’m your English coach. Let’s practice ${sc}. I’ll respond naturally, correct you gently, and ask follow-up questions. ${firstQuestion(sc)}`}],answers:[],active:true,started:new Date().toISOString()};
  renderSpeakChat();
  speakText(speakingSession.msgs[0].text);
}
function firstQuestion(sc){
  if(sc.includes('Job'))return 'Imagine I am the interviewer. Tell me about yourself and the type of role you want.';
  if(sc.includes('Business'))return 'Give me a project update: what is going well, what is blocked, and what support do you need?';
  if(sc.includes('Hotel'))return 'You arrive at a hotel and your reservation is missing. What would you say to solve the problem politely?';
  if(sc.includes('Audit'))return 'Explain a nonconformity, the risk, and the corrective action you would propose.';
  if(sc.includes('TOEFL'))return 'Do you agree or disagree that online learning is more effective than classroom learning? Give reasons and examples.';
  return 'Tell me about your day. What happened, how did you feel, and what did you learn?';
}
function renderSpeakChat(){
  let area=document.getElementById('speakArea');if(!area)return;
  if(!speakingSession){area.innerHTML='';return}
  let transcript=speakingSession.msgs.map(m=>`<div class="bubble ${m.role==='ai'?'ai':'me'}"><b>${m.role==='ai'?'Coach':'You'}:</b> ${esc(m.text)}</div>`).join('');
  area.innerHTML=`<div class="speak-chat" id="chatBox">${transcript}</div>
  <div class="micbar"><div class="row" style="justify-content:space-between;align-items:center"><div><span id="micDot" class="mic-pulse ${micOn?'on':''}"></span> <span class="status" id="micStatus">${micOn?'Escuchando: habla después del beep':'Micrófono apagado'}</span></div><div class="row"><button class="btn hot small" onclick="toggleConversationMic()">${micOn?'⏹ Detener':'🎙️ Activar modo voz'}</button><button class="btn green small" onclick="finishSpeakingSession()">Finalizar y recibir feedback</button></div></div>
  <div id="interim" class="interim-box tiny"></div>
  <details style="margin-top:9px"><summary class="tiny">Modo escritura / teclado por voz</summary><textarea id="fallbackText" class="field" placeholder="Write or dictate with your phone keyboard..."></textarea><button class="btn small secondary" onclick="sendSpeakingAnswer(document.getElementById('fallbackText').value);document.getElementById('fallbackText').value=''">Enviar texto</button></details>
  <div class="tiny" style="margin-top:7px">Tip: responde con 2–4 oraciones. Usa: point + reason + example.</div></div>`;
  let cb=document.getElementById('chatBox');if(cb)cb.scrollTop=cb.scrollHeight;
}
async function toggleConversationMic(){
  if(micOn){stopConversationMic();return}
  let ok=await ensureMic();if(!ok)return;
  if(!getRecognizer()){toast('Tu navegador permite audio, pero no dictado automático. Usa Chrome/Edge o el modo escritura.');return}
  autoListen=true;micOn=true;renderSpeakChat();beep();setTimeout(listenOnce,350);
}
function stopConversationMic(){
  autoListen=false;micOn=false;
  if(window._listenTimer)clearTimeout(window._listenTimer);
  if(recognition){try{recognition.onend=null;recognition.onerror=null;recognition.onresult=null;recognition.stop()}catch(e){}}
  recognition=null;
  let st=document.getElementById('micStatus');if(st)st.textContent='Micrófono apagado';
  let dot=document.getElementById('micDot');if(dot)dot.classList.remove('on');
}
function beep(){
  try{let ctx=new (window.AudioContext||window.webkitAudioContext)();let o=ctx.createOscillator();let g=ctx.createGain();o.frequency.value=740;g.gain.value=.045;o.connect(g);g.connect(ctx.destination);o.start();setTimeout(()=>{o.stop();ctx.close()},120)}catch(e){}
}
function listenOnce(){
  if(!autoListen||!speakingSession)return;
  let r=getRecognizer();recognition=r;
  if(!r){stopConversationMic();toast('Dictado no disponible en este navegador.');return}
  let finalText='';let heard=false;
  r.onstart=()=>{let st=document.getElementById('micStatus');if(st)st.textContent='Escuchando... habla ahora';let it=document.getElementById('interim');if(it)it.textContent=''};
  r.onresult=e=>{
    let interim='';
    for(let i=e.resultIndex;i<e.results.length;i++){
      let txt=e.results[i][0].transcript;
      if(e.results[i].isFinal){finalText+=txt+' ';heard=true}else interim+=txt;
    }
    let it=document.getElementById('interim');
    if(it)it.innerHTML=(finalText||interim)?`<b>Detectado:</b> ${esc((finalText+interim).trim())}`:'Escuchando...';
  };
  r.onerror=e=>{
    let err=friendlyMicError(e.error);
    let st=document.getElementById('micStatus');if(st)st.textContent='Micrófono: '+err;
    if(e.error==='not-allowed'||e.error==='service-not-allowed'||e.error==='audio-capture'){stopConversationMic();return}
  };
  r.onend=()=>{
    if(!autoListen||!speakingSession)return;
    let text=finalText.trim();
    if(text){sendSpeakingAnswer(text,true);return}
    window._listenTimer=setTimeout(()=>{if(autoListen){beep();listenOnce()}},700);
  };
  try{r.start()}catch(e){window._listenTimer=setTimeout(()=>{if(autoListen)listenOnce()},900)}
}
function sendSpeakingAnswer(txt,fromMic){
  txt=String(txt||'').trim();
  if(!txt){toast('No detecté audio claro. Habla más cerca del micrófono o usa modo escritura.');return}
  if(!speakingSession)return;
  speakingSession.msgs.push({role:'me',text:txt});
  speakingSession.answers.push(txt);
  speakingSession.turn++;
  let analysis=analyzeEnglish(txt,speakingSession.scenario);
  let follow=coachReply(txt,speakingSession.turn,speakingSession.scenario,analysis);
  speakingSession.msgs.push({role:'ai',text:follow});
  renderSpeakChat();
  if(autoListen&&fromMic){try{recognition&&recognition.stop()}catch(e){};speakText(follow,()=>{if(autoListen){beep();setTimeout(listenOnce,650)}})}else speakText(follow);
}
function analyzeEnglish(txt,sc){
  let low=txt.toLowerCase();let corrections=[];let upgrades=[];let words=txt.split(/\s+/).filter(Boolean).length;
  const add=(bad,good)=>{if(low.includes(bad))corrections.push(`Instead of “${bad}”, say “${good}”.`)};
  add('i am agree','I agree');add('i have 30 years','I am 30 years old');add('more better','better');add('people is','people are');add('depend of','depends on');add('discuss about','discuss');add('explain me','explain it to me');add('make a decision','make a decision');
  if(/^give\b/i.test(txt)) upgrades.push('A more polite professional opening: “Could you share…” or “Could you give me…”');
  if(!/[.!?]$/.test(txt)) upgrades.push('Try finishing your thought with a clear complete sentence.');
  if(words<8) upgrades.push('Make it fuller: answer + reason + example.');
  if(!/because|for example|for instance|however|although|so|therefore|in my opinion|from my perspective/i.test(txt)) upgrades.push('Add a connector such as “because”, “for example”, or “from my perspective”.');
  return {corrections,upgrades,words};
}
function coachReply(txt,turn,sc,analysis){
  let lower=txt.toLowerCase();
  let natural=naturalResponse(txt,sc);
  let correction='';
  if(analysis.corrections.length) correction+=' Quick correction: '+analysis.corrections[0];
  else if(analysis.upgrades.length) correction+=' Small upgrade: '+analysis.upgrades[0];
  let next=nextQuestion(txt,turn,sc);
  if(turn>=7) return `${natural} ${correction} We have enough material now. Tap “Finalizar” and I’ll give you detailed feedback, score, corrections, and phrases to practice.`;
  return `${natural} ${correction} ${next}`.replace(/\s+/g,' ').trim();
}
function naturalResponse(txt,sc){
  let l=txt.toLowerCase();
  if(/\?/.test(txt)||/^(what|how|why|when|where|can|could|would|do|does|is|are|give|tell|explain)\b/i.test(txt)){
    if(l.includes('interview')||sc.includes('Job'))return 'Sure. For a job interview, focus on clarity, confidence, and evidence: explain who you are, what you achieved, how you solved problems, why you fit the role, and ask one smart question at the end.';
    if(l.includes('tips'))return 'Yes. My top tips are: answer directly, give one concrete example, quantify results when possible, avoid memorized answers, and close with a confident next step.';
    if(l.includes('toefl'))return 'For TOEFL-style speaking, structure your answer in three parts: opinion, two reasons, and one example. Fluency matters more than perfect vocabulary.';
    return 'Good question. I’ll answer briefly, and then I want you to react in English so we keep the conversation active.';
  }
  if(l.includes('nervous')||l.includes('afraid'))return 'That is very common, and it is a good topic to practice. The goal is not to sound perfect; the goal is to communicate clearly under pressure.';
  if(l.includes('work')||l.includes('project'))return 'That sounds practical. In a professional conversation, try to make your message specific: what happened, what impact it had, and what action you recommend.';
  if(l.includes('i think')||l.includes('in my opinion'))return 'Nice. You are giving an opinion, which is exactly what fluency practice needs.';
  return 'I understand. Let me help you make that sound more natural and complete.';
}
function nextQuestion(txt,turn,sc){
  const job=['What is one achievement you can prove with numbers or results?','How would you answer: why should we hire you?','Tell me about a difficult situation at work and how you handled it.','What question would you ask the interviewer at the end?'];
  const business=['What is the main risk right now?','What decision do you need from the team?','How would you summarize that in one executive sentence?','What action will you take next?'];
  const daily=['Why was that important to you?','What happened next?','How would you describe it using more emotional vocabulary?','Can you tell me the same idea in a shorter, clearer way?'];
  const toefl=['Give your first reason and one example.','Now give a second reason.','Can you summarize your answer in one strong final sentence?','Would an opposite opinion be reasonable? Why?'];
  let arr=sc.includes('Job')?job:sc.includes('Business')||sc.includes('Audit')?business:sc.includes('TOEFL')?toefl:daily;
  return arr[(turn-1)%arr.length];
}
function finishSpeakingSession(){
  if(!speakingSession)return;
  stopConversationMic();
  let all=speakingSession.answers.join(' ');
  let wordCount=all.split(/\s+/).filter(Boolean).length;
  let analyses=speakingSession.answers.map(a=>analyzeEnglish(a,speakingSession.scenario));
  let corrections=[...new Set(analyses.flatMap(a=>a.corrections))];
  let upgrades=[...new Set(analyses.flatMap(a=>a.upgrades))];
  let score=Math.min(100,Math.round(45+Math.min(30,wordCount/3)+(corrections.length?5:15)+(upgrades.length?5:10)));
  let tips=[];
  if(wordCount<90)tips.push('Extend your answers: use point + reason + example + result.');
  if(!/because|for example|for instance|however|although|therefore|from my perspective/i.test(all))tips.push('Use connectors: because, for example, however, from my perspective.');
  if(corrections.length)tips.push('Review these corrections: '+corrections.slice(0,4).join(' '));
  tips.push('Useful phrases: “What I would emphasize is…”, “The main reason is…”, “A concrete example is…”, “The impact was…”.');
  tips.push('Pronunciation: speak in chunks, stress key words, and finish final consonants clearly.');
  let feedback=`Final feedback. Score: ${score}/100. You communicated your ideas ${score>=75?'clearly':'with potential, but you need fuller answers'}. ${tips.join(' ')}`;
  speakingSession.msgs.push({role:'ai',text:feedback});
  state.speakingSessions.push({date:new Date().toISOString(),scenario:speakingSession.scenario,answers:speakingSession.answers,score,tips,corrections,upgrades});
  state.xp+=45;markDaily('speaking');save();renderSpeakChat();speakText(feedback);toast('Speaking guardado +45 XP');
}

function renderPractice(){document.getElementById('practice').innerHTML=`<div class="cover"><h2>Práctica diaria</h2><p>Listening, pronunciación, vocabulario y juegos rápidos para reforzar memoria.</p></div><div class="card"><h3>Listening Lab</h3><div class="row"><select id="listenLevel" class="field" style="flex:1">${LEVELS.map(l=>`<option ${l===selectedLevel?'selected':''}>${l}</option>`).join('')}</select><button class="btn" onclick="openListeningExercise()">Abrir ejercicio</button></div><div id="listenBox"></div></div><div class="card"><h3>Pronunciation Coach</h3><p class="tiny">Escucha, repite y dicta. Trabaja sonidos difíciles.</p><select id="pronPhrase" class="field"><option>think, three, thirty-three</option><option>very good vocabulary</option><option>I worked, played, and wanted</option><option>world, girl, early</option><option>Can you clarify the main reason?</option></select><div class="row" style="margin-top:10px"><button class="btn gold" onclick="speakText(document.getElementById('pronPhrase').value)">▶ Modelo</button><button class="btn hot" onclick="startMicToField('pronOut')">🎙️ Repetir</button></div><textarea id="pronOut" class="field" placeholder="Dictado de tu pronunciación..."></textarea></div><div class="card"><h3>Vocabulario personal</h3><div class="grid2"><input id="newWord" class="field" placeholder="word"><input id="newTrans" class="field" placeholder="traducción / nota"></div><button class="btn secondary full" style="margin-top:10px" onclick="addWord(document.getElementById('newWord').value,document.getElementById('newTrans').value,'Manual');document.getElementById('newWord').value='';document.getElementById('newTrans').value=''">Agregar palabra</button><div id="vocabGame"></div><button class="btn gold full" style="margin-top:10px" onclick="renderVocabGame()">Juego rápido</button></div>`}
function openListeningExercise(){let lvl=document.getElementById('listenLevel').value;let done=state.listeningDone.filter(x=>x.startsWith(lvl+'-')).length;let n=Math.min(done+1,100);let long=Math.ceil(n/15);let text=`${lvl} listening exercise ${n}. ${'English improves when you listen actively, identify key words, and repeat useful phrases. '.repeat(long)}The main idea is that practice must be consistent and meaningful.`;document.getElementById('listenBox').innerHTML=`<div class="qa"><b>${lvl} Listening ${n}/100</b><p class="tiny">La extensión aumenta progresivamente.</p><button class="btn gold full" onclick="speakText('${esc(text)}')">▶ Reproducir audio</button><textarea id="listenAns" class="field" placeholder="What is the main idea?"></textarea><button class="btn green" onclick="completeListening('${lvl}-${n}')">Guardar listening</button></div>`}
function completeListening(id){if(!state.listeningDone.includes(id))state.listeningDone.push(id);state.xp+=12;markDaily('listening');save();toast('Listening completado +12 XP')}
function renderVocabGame(){let voc=state.vocab.slice(-8);let box=document.getElementById('vocabGame');if(voc.length<3){box.innerHTML='<p class="tiny">Agrega al menos 3 palabras para jugar.</p>';return}let v=voc[Math.floor(Math.random()*voc.length)];box.innerHTML=`<div class="qa"><b>Completa:</b> The word means “${esc(v.translation||v.source||'your saved word')}”.<input id="gameAns" class="field" placeholder="type the word"><button class="btn small" onclick="document.getElementById('gameAns').value.toLowerCase().trim()==='${esc(v.word)}'? (state.xp+=10,save(),toast('Correcto +10 XP')):toast('Respuesta: ${esc(v.word)}')">Revisar</button></div>`}
function openPlacement(){let box=document.getElementById('lessonModal');box.innerHTML=`<div class="lesson-sheet"><div class="lesson-hero"><div class="row" style="justify-content:space-between"><span class="pill dark">Diagnóstico CEFR interno</span><button class="btn small secondary" onclick="closeLesson()">Cerrar</button></div><h2>Test de ubicación</h2><p>Responde las preguntas. El resultado ajusta tu nivel sugerido dentro de la app.</p></div><div class="card"><div id="placementQs">${PLACEMENT.map((q,i)=>`<div class="placement-q"><b>${i+1}. ${esc(q.q)}</b>${q.options.map((o,j)=>`<label class="option"><input type="radio" name="pl${i}" value="${j}"> ${esc(o)}</label>`).join('')}</div>`).join('')}</div><button class="btn green full" onclick="gradePlacement()">Calcular nivel</button><div id="placementResult"></div></div></div>`;box.classList.add('show')}
function gradePlacement(){let score=0,by={A1:0,A2:0,B1:0,B2:0,C1:0,C2:0};PLACEMENT.forEach((q,i)=>{let r=document.querySelector(`input[name=pl${i}]:checked`);if(r&&+r.value===q.answer){score++;by[q.level]++}});let lvl='A1';if(score>=22)lvl='C2';else if(score>=18)lvl='C1';else if(score>=14)lvl='B2';else if(score>=10)lvl='B1';else if(score>=6)lvl='A2';state.placement={score,level:lvl,date:new Date().toISOString(),by};state.profile.level=lvl;selectedLevel=lvl;let ps=loadProfiles().map(p=>p.id===state.profile.id?state.profile:p);saveProfiles(ps);state.xp+=50;save();document.getElementById('placementResult').innerHTML=`<div class="note"><b>Nivel sugerido: ${lvl}</b><br>Puntaje: ${score}/${PLACEMENT.length}. Se actualizó tu ruta inicial.</div>`;renderAll()}
function renderProgress(){let done=state.doneModules.length;document.getElementById('progress').innerHTML=`<div class="cover"><h2>Progreso y certificados</h2><p>Consulta medallas, avances, vocabulario y exámenes de nivel.</p></div><div class="grid2"><div class="card"><h3>Resumen</h3><p><b>Estudiante:</b> ${esc(state.profile.name)}</p><p><b>Nivel:</b> ${esc(state.profile.level)}</p><p><b>XP:</b> ${state.xp}</p><p><b>Módulos:</b> ${done}/600</p><p><b>Speaking:</b> ${state.speakingSessions.length} sesiones</p><p><b>Listening:</b> ${state.listeningDone.length}/600</p></div><div class="card"><h3>Guardado</h3><p class="tiny">El avance se guarda automáticamente en este navegador. Exporta un respaldo si cambiarás de dispositivo.</p><button class="btn secondary" onclick="logout()">Cambiar usuario</button><button class="btn" onclick="exportProgress()">Exportar progreso</button><input type="file" class="field" onchange="importProgress(event)" accept="application/json"></div></div><div class="card"><h3>Medallas</h3><div class="badge-shelf">${LEVELS.map(l=>medalsForLevel(l,TOPICS.filter(t=>t.level===l&&state.doneModules.includes(t.id)).length)).join('')}</div></div><div class="card"><h3>Banco de vocabulario</h3>${state.vocab.length?state.vocab.map(v=>`<div class="task"><div class="ticon">🔤</div><div><strong>${esc(v.word)}</strong><small>${esc(v.translation||'Sin traducción')} · ${esc(v.source||'')}</small></div><button class="btn small secondary" onclick="speakText('${esc(v.word)}')">🔊</button></div>`).join(''):'<p class="tiny">Aún no hay palabras. Toca palabras en lecturas o agrégalas manualmente.</p>'}</div><div class="card"><h3>Examen y certificado por nivel</h3>${LEVELS.map(l=>`<button class="btn secondary" style="margin:4px" onclick="openLevelExam('${l}')">Examen ${l}</button>`).join('')}<div id="examBox"></div></div>`}
function openLevelExam(level){let box=document.getElementById('examBox');let t=TOPICS.find(x=>x.level===level);box.innerHTML=`<h4>${level} Level Boss Test</h4><p class="tiny">Aprueba con 80% para emitir certificado interno.</p>${[1,2,3,4,5].map((_,i)=>`<div class="qa"><b>${i+1}. ${['Grammar: write 3 correct sentences.','Reading: summarize a short text.','Listening: play and identify the main idea.','Speaking: write what you would say in 60 seconds.','Writing: write a structured paragraph.'][i]}</b>${i===2?`<button class="btn small gold" onclick="speakText('This is a level ${level} listening task. A successful learner understands the main idea, identifies details, and responds clearly.')">▶ Audio</button>`:''}<textarea id="ex${i}" class="field"></textarea></div>`).join('')}<button class="btn green full" onclick="gradeLevel('${level}')">Calificar y emitir certificado</button>`}
function gradeLevel(level){let score=0;for(let i=0;i<5;i++){let words=(document.getElementById('ex'+i).value||'').trim().split(/\s+/).filter(Boolean).length;if(words>=10)score+=20}if(score>=80){let cert={id:uid(),level,score,date:new Date().toISOString(),name:state.profile.name};state.certificates.push(cert);state.xp+=100;save();document.getElementById('examBox').insertAdjacentHTML('beforeend',certificateHTML(cert,true));toast('Certificado emitido')}else{document.getElementById('examBox').insertAdjacentHTML('beforeend',`<div class="dangerbox">Resultado: ${score}/100. Se requiere 80.</div>`)} }
function certificateHTML(c,buttons){return `<div class="certificate"><h2>Certificate of English Competence</h2><p>This certifies that</p><div class="name">${esc(c.name)}</div><p>completed the Fluentia IA internal assessment for</p><div class="level">${esc(c.level)}</div><p>Score: <b>${c.score}/100</b> · ${new Date(c.date).toLocaleDateString()}</p><p class="tiny">Internal learning certificate. Not an official CEFR, TOEFL or ETS certificate.</p>${buttons?`<button class="btn gold" onclick="downloadCertificate('${c.id}')">Descargar</button>`:''}</div>`}
function downloadCertificate(id){let c=state.certificates.find(x=>x.id===id);let doc=`<!doctype html><meta charset="utf-8"><title>Certificate</title><body>${certificateHTML(c,false)}</body>`;let a=document.createElement('a');a.href=URL.createObjectURL(new Blob([doc],{type:'text/html'}));a.download=`Fluentia_Certificate_${c.level}_${c.name.replace(/\s+/g,'_')}.html`;a.click()}
function logout(){stopConversationMic();currentId=null;state=null;document.getElementById('app').classList.add('hidden');document.getElementById('auth').classList.remove('hidden');renderProfiles()}
function exportProgress(){let a=document.createElement('a');a.href=URL.createObjectURL(new Blob([JSON.stringify(state,null,2)],{type:'application/json'}));a.download='fluentia_progress_'+state.profile.name.replace(/\s+/g,'_')+'.json';a.click()}
function importProgress(ev){let f=ev.target.files[0];if(!f)return;let r=new FileReader();r.onload=()=>{try{state=JSON.parse(r.result);currentId=state.profile.id;localStorage.setItem('fluentia_state_'+currentId,JSON.stringify(state));let p=loadProfiles();if(!p.find(x=>x.id===currentId)){p.push(state.profile);saveProfiles(p)}save();initApp()}catch(e){toast('Archivo inválido')}};r.readAsText(f)}
window.addEventListener('load',renderProfiles);

