function startSpeakingSession(){
  const sc=document.getElementById('spScenario')?.value || 'Natural English conversation';
  speakingSession={
    scenario:sc,
    turn:0,
    msgs:[{role:'ai',text:`Hi! I'm your English coach. You can talk to me naturally. Say hello, ask for advice, or ask me to simulate a job interview. I’ll respond, correct you, and help you sound more fluent.`}],
    answers:[],
    active:true,
    started:new Date().toISOString(),
    usingRealAI:false
  };
  renderSpeakChat();
  speakText(speakingSession.msgs[0].text);
}

function renderSpeakChat(){
  const area=document.getElementById('speakArea'); if(!area) return;
  if(!speakingSession){area.innerHTML='';return}
  const transcript=speakingSession.msgs.map(m=>`<div class="bubble ${m.role==='ai'?'ai':'me'}"><b>${m.role==='ai'?'Coach':'You'}:</b> ${esc(m.text)}</div>`).join('');
  const modeLabel = speakingSession.usingRealAI ? 'IA real conectada' : (aiOnlineStatus==='missing_key' ? 'Falta OPENAI_API_KEY' : 'Modo local / esperando IA');
  area.innerHTML=`<div class="speak-chat" id="chatBox">${transcript}</div>
  <div class="micbar"><div class="row" style="justify-content:space-between;align-items:center">
    <div><span id="micDot" class="mic-pulse ${micOn?'on':''}"></span> <span class="status" id="micStatus">${micOn?'Escuchando con micrófono...':'Micrófono apagado'}</span><br><span class="tiny">${esc(modeLabel)}</span></div>
    <div class="row"><button class="btn hot small" onclick="toggleConversationMic()">${micOn?'⏹ Detener voz':'🎙️ Hablar'}</button><button class="btn green small" onclick="finishSpeakingSession()">Finalizar y feedback</button></div>
  </div>
  <div id="interim" class="interim-box tiny"></div>
  <details style="margin-top:9px" open><summary class="tiny">También puedes escribir o usar el dictado del teclado</summary><textarea id="fallbackText" class="field" placeholder="Type here, for example: Give me 5 tips for a job interview..."></textarea><button class="btn small secondary" onclick="sendSpeakingAnswer(document.getElementById('fallbackText').value);document.getElementById('fallbackText').value=''">Enviar</button></details>
  <div class="tiny" style="margin-top:7px">La conversación real requiere API. El micrófono usa grabación + transcripción por servidor para funcionar mejor en móvil y PC.</div></div>`;
  const cb=document.getElementById('chatBox'); if(cb) cb.scrollTop=cb.scrollHeight;
}

async function toggleConversationMic(){
  if(micOn){stopConversationMic();return}
  const ok=await ensureMic(); if(!ok) return;
  autoListen=true; micOn=true; renderSpeakChat(); beep();
  if(window.MediaRecorder){
    setTimeout(beginServerVoiceTurn,350);
  }else if(getRecognizer()){
    setTimeout(listenOnce,350);
  }else{
    stopConversationMic();
    toast('Tu navegador no soporta grabación de audio. Usa el teclado por voz del celular.');
  }
}

function stopConversationMic(){
  autoListen=false; micOn=false; voiceTurnBusy=false;
  if(window._listenTimer) clearTimeout(window._listenTimer);
  try{ if(recognition){recognition.onend=null; recognition.onerror=null; recognition.onresult=null; recognition.stop();} }catch(e){}
  recognition=null;
  stopVoiceCaptureOnly();
  const st=document.getElementById('micStatus'); if(st) st.textContent='Micrófono apagado';
  const dot=document.getElementById('micDot'); if(dot) dot.classList.remove('on');
}

function stopVoiceCaptureOnly(){
  try{ if(voiceRaf) cancelAnimationFrame(voiceRaf); }catch(e){}
  voiceRaf=null;
  try{ if(voiceRecorder && voiceRecorder.state!=='inactive') voiceRecorder.stop(); }catch(e){}
  try{ if(voiceStream) voiceStream.getTracks().forEach(t=>t.stop()); }catch(e){}
  try{ if(voiceAudioCtx) voiceAudioCtx.close(); }catch(e){}
  voiceRecorder=null; voiceStream=null; voiceAudioCtx=null; voiceAnalyser=null;
}

function preferredMime(){
  const types=['audio/webm;codecs=opus','audio/webm','audio/mp4','audio/ogg;codecs=opus'];
  if(!window.MediaRecorder) return '';
  return types.find(t=>MediaRecorder.isTypeSupported(t)) || '';
}

async function beginServerVoiceTurn(){
  if(!autoListen || !speakingSession || voiceTurnBusy) return;
  voiceTurnBusy=true;
  const st=document.getElementById('micStatus'); if(st) st.textContent='Escuchando... habla ahora';
  const it=document.getElementById('interim'); if(it) it.innerHTML='<b>Escuchando:</b> habla y haz una pausa al terminar.';
  try{
    voiceStream=await navigator.mediaDevices.getUserMedia({audio:{echoCancellation:true,noiseSuppression:true,autoGainControl:true}});
    voiceChunks=[];
    const mime=preferredMime();
    voiceRecorder = mime ? new MediaRecorder(voiceStream,{mimeType:mime}) : new MediaRecorder(voiceStream);
    voiceRecorder.ondataavailable = e => { if(e.data && e.data.size>0) voiceChunks.push(e.data); };
    voiceRecorder.onerror = () => { if(st) st.textContent='Error grabando audio'; voiceTurnBusy=false; };
    voiceRecorder.onstop = async () => {
      try{ if(voiceStream) voiceStream.getTracks().forEach(t=>t.stop()); }catch(e){}
      try{ if(voiceAudioCtx) voiceAudioCtx.close(); }catch(e){}
      const blob = new Blob(voiceChunks,{type:voiceRecorder?.mimeType || mime || 'audio/webm'});
      if(blob.size < 1500){
        if(st) st.textContent='No detecté voz clara. Intenta de nuevo.';
        voiceTurnBusy=false;
        if(autoListen) setTimeout(beginServerVoiceTurn,800);
        return;
      }
      if(st) st.textContent='Transcribiendo tu voz...';
      const text = await transcribeAudioBlob(blob);
      voiceTurnBusy=false;
      if(text){
        const tx=document.getElementById('interim'); if(tx) tx.innerHTML=`<b>Detectado:</b> ${esc(text)}`;
        sendSpeakingAnswer(text,true);
      }else{
        if(st) st.textContent='No pude transcribir. Usa texto o revisa la API.';
        if(autoListen) setTimeout(beginServerVoiceTurn,1200);
      }
    };
    voiceRecorder.start(250);
    monitorSilenceAndStop(voiceStream, voiceRecorder);
  }catch(e){
    voiceTurnBusy=false;
    if(st) st.textContent='No se pudo iniciar el micrófono: '+(e.name||e.message||'error');
    toast('No se pudo iniciar el micrófono. Revisa permisos del navegador.');
    if(getRecognizer()) setTimeout(listenOnce,500);
  }
}

function monitorSilenceAndStop(stream, recorder){
  try{
    voiceAudioCtx=new (window.AudioContext||window.webkitAudioContext)();
    const source=voiceAudioCtx.createMediaStreamSource(stream);
    voiceAnalyser=voiceAudioCtx.createAnalyser();
    voiceAnalyser.fftSize=2048;
    source.connect(voiceAnalyser);
    const data=new Uint8Array(voiceAnalyser.fftSize);
    const started=Date.now(); let lastVoice=Date.now(); let heard=false;
    const tick=()=>{
      if(!recorder || recorder.state==='inactive') return;
      voiceAnalyser.getByteTimeDomainData(data);
      let sum=0; for(let i=0;i<data.length;i++){let v=(data[i]-128)/128; sum+=v*v;}
      const rms=Math.sqrt(sum/data.length);
      const it=document.getElementById('interim');
      if(rms>0.025){ heard=true; lastVoice=Date.now(); if(it) it.innerHTML='<b>Detectando voz...</b> sigue hablando.'; }
      if(heard && Date.now()-lastVoice>1300 && Date.now()-started>900){ try{recorder.stop();}catch(e){}; return; }
      if(Date.now()-started>18000){ try{recorder.stop();}catch(e){}; return; }
      voiceRaf=requestAnimationFrame(tick);
    };
    tick();
  }catch(e){
    setTimeout(()=>{ try{ if(recorder.state!=='inactive') recorder.stop(); }catch(err){} },8000);
  }
}

function blobToBase64(blob){
  return new Promise((resolve,reject)=>{
    const reader=new FileReader();
    reader.onloadend=()=>resolve(String(reader.result).split(',')[1] || '');
    reader.onerror=reject;
    reader.readAsDataURL(blob);
  });
}

async function transcribeAudioBlob(blob){
  try{
    const b64=await blobToBase64(blob);
    const res=await fetch('/.netlify/functions/transcribe',{
      method:'POST',
      headers:{'Content-Type':'application/json'},
      body:JSON.stringify({audio:b64,mimeType:blob.type||'audio/webm'})
    });
    const data=await res.json().catch(()=>({}));
    if(!res.ok){
      aiOnlineStatus=data.setupRequired?'missing_key':'transcription_error';
      toast(data.setupRequired?'Falta OPENAI_API_KEY en Netlify para transcribir audio.':'No pude transcribir audio: '+(data.error||res.status));
      return '';
    }
    return (data.text||'').trim();
  }catch(e){
    toast('No se pudo conectar con la función de transcripción.');
    return '';
  }
}

async function sendSpeakingAnswer(txt,fromMic){
  txt=String(txt||'').trim();
  if(!txt){toast('No detecté audio claro. Habla más cerca o usa el modo escritura.');return}
  if(!speakingSession) return;
  speakingSession.msgs.push({role:'me',text:txt});
  speakingSession.answers.push(txt);
  speakingSession.turn++;
  speakingSession.msgs.push({role:'ai',text:'Thinking...'});
  renderSpeakChat();
  const reply = await getAiCoachReply(false);
  speakingSession.msgs[speakingSession.msgs.length-1]={role:'ai',text:reply};
  renderSpeakChat();
  if(autoListen&&fromMic){
    speakText(reply,()=>{ if(autoListen){ beep(); setTimeout(beginServerVoiceTurn,650); } });
  }else speakText(reply);
}

async function getAiCoachReply(finalFeedback){
  try{
    const res=await fetch('/.netlify/functions/ai-coach',{
      method:'POST',
      headers:{'Content-Type':'application/json'},
      body:JSON.stringify({
        scenario:speakingSession?.scenario||'Natural English conversation',
        level:state?.profile?.level||'B2',
        studentName:state?.profile?.name||'student',
        messages:(speakingSession?.msgs||[]).filter(m=>m.text!=='Thinking...'),
        finalFeedback:!!finalFeedback
      })
    });
    const data=await res.json().catch(()=>({}));
    if(res.ok && data.reply){ speakingSession.usingRealAI=true; aiOnlineStatus='openai'; return data.reply.trim(); }
    aiOnlineStatus=data.setupRequired?'missing_key':'ai_error';
    return localCoachReply((speakingSession?.msgs||[]).filter(m=>m.role==='me').slice(-1)[0]?.text||'', finalFeedback, data.error);
  }catch(e){
    aiOnlineStatus='network_error';
    return localCoachReply((speakingSession?.msgs||[]).filter(m=>m.role==='me').slice(-1)[0]?.text||'', finalFeedback, e.message);
  }
}

function localCoachReply(txt, finalFeedback, error){
  const l=String(txt||'').toLowerCase();
  if(finalFeedback){
    const all=(speakingSession?.answers||[]).join(' ');
    const words=all.split(/\s+/).filter(Boolean).length;
    return `Final feedback: your communication was understandable, but this is the limited local coach because the real AI is not connected yet. Score: ${Math.min(85,45+Math.floor(words/3))}/100. Strength: you are practicing real interaction. Tip: answer with point + reason + example. Better phrase: instead of short commands, say “Could you give me...” or “Could we practice...”. To get ChatGPT-like feedback, configure OPENAI_API_KEY in Netlify.`;
  }
  if(/^(hi|hello|hey|good morning|good afternoon)\b/.test(l)) return `Hello! Great to see you. What would you like to practice today: a job interview, daily conversation, business English, or pronunciation?`;
  if(/5.*tips|five.*tips|tips.*interview|job interview tips|interview/.test(l) && !/simulation|simulate|role.?play|mock/.test(l)) return `Absolutely. Here are five strong tips for a job interview: 1) answer clearly and directly, 2) support your answers with a real example, 3) mention measurable results when possible, 4) show confidence without sounding arrogant, and 5) prepare one smart question for the interviewer. Better phrase: “Could you give me five tips for a job interview?” Would you like to practice one answer now?`;
  if(/simulat|simulation|role.?play|mock interview|interview practice/.test(l)) return `Of course. Let’s do a job interview simulation. I’ll be the interviewer and I’ll give you feedback after each answer. First question: Tell me about yourself and explain why you are interested in this position.`;
  if(/thank/.test(l)) return `You’re welcome. Quick upgrade: you can also say “Thanks, that’s helpful” or “I appreciate the advice.” What would you like to practice next?`;
  return `I understand your idea. Quick upgrade: try to make it a complete sentence with a reason. For example: “I think this is important because...” Now tell me one specific example related to what you just said. Note: real AI is not connected yet, so this local mode is limited. ${error?`(${error})`:''}`;
}

async function finishSpeakingSession(){
  if(!speakingSession) return;
  stopConversationMic();
  speakingSession.msgs.push({role:'ai',text:'Preparing your feedback...'});
  renderSpeakChat();
  const feedback=await getAiCoachReply(true);
  speakingSession.msgs[speakingSession.msgs.length-1]={role:'ai',text:feedback};
  const all=speakingSession.answers.join(' ');
  const score=Math.min(100,Math.max(50,Math.round(55+all.split(/\s+/).filter(Boolean).length/3)));
  state.speakingSessions.push({date:new Date().toISOString(),scenario:speakingSession.scenario,answers:speakingSession.answers,score,tips:[feedback],corrections:[],upgrades:[],realAI:!!speakingSession.usingRealAI});
  state.xp+=45; markDaily('speaking'); save(); renderSpeakChat(); speakText(feedback); toast('Speaking guardado +45 XP');
}


